import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { instructorAPI } from '../../api/client';
import styles from './Instructor.module.css';

// ── Helpers ───────────────────────────────────────────────────────────────────
const DAYS   = ['ПН', 'ВТ', 'СР', 'ЧТ', 'ПТ', 'СБ', 'ВС'];
const MONTHS = ['ЯНВАРЬ','ФЕВРАЛЬ','МАРТ','АПРЕЛЬ','МАЙ','ИЮНЬ',
                'ИЮЛЬ','АВГУСТ','СЕНТЯБРЬ','ОКТЯБРЬ','НОЯБРЬ','ДЕКАБРЬ'];

function getWeekDates(offset = 0) {
  const today  = new Date();
  const dow    = (today.getDay() + 6) % 7;
  const monday = new Date(today);
  monday.setDate(today.getDate() - dow + offset * 7);
  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(monday);
    d.setDate(monday.getDate() + i);
    return d;
  });
}

function toDateStr(d) {
  return d.toISOString().slice(0, 10);
}

function fmtDate(d) {
  return [
    String(d.getDate()).padStart(2, '0'),
    String(d.getMonth() + 1).padStart(2, '0'),
    d.getFullYear(),
  ].join('.');
}

// ── Spinner ───────────────────────────────────────────────────────────────────
function Spinner() {
  return <div className={styles.spinner} />;
}

// ═══════════════════════════════════════════════════════════════════════════════
// SCHEDULE TAB
// ═══════════════════════════════════════════════════════════════════════════════

function CreateSlotModal({ selectedDate, onClose, onSaved }) {
  const [form, setForm]     = useState({ start_time: '10:00', end_time: '12:00' });
  const [loading, setLoading] = useState(false);
  const [err, setErr]       = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try {
      await instructorAPI.createSlot({ date: selectedDate, ...form });
      onSaved();
    } catch (e) {
      setErr(e.response?.data?.detail || JSON.stringify(e.response?.data) || 'Ошибка');
    } finally { setLoading(false); }
  };

  return (
    <div className={styles.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div className={styles.modal}>
        <div className={styles.modalHeader}>
          <span className={styles.modalTitle}>Новый слот</span>
          <button className={styles.modalClose} onClick={onClose}>✕</button>
        </div>

        <div className={styles.field}>
          <label className={styles.label}>Дата</label>
          <div className={`${styles.input} ${styles.inputReadonly}`}>
            {selectedDate.split('-').reverse().join('.')}
          </div>
        </div>

        <div className={styles.field}>
          <label className={styles.label}>Время</label>
          <div className={styles.timeGrid}>
            <div>
              <label className={styles.labelSm}>Начало</label>
              <input className={styles.input} type="time" value={form.start_time}
                onChange={e => setForm(p => ({ ...p, start_time: e.target.value }))} />
            </div>
            <div>
              <label className={styles.labelSm}>Конец</label>
              <input className={styles.input} type="time" value={form.end_time}
                onChange={e => setForm(p => ({ ...p, end_time: e.target.value }))} />
            </div>
          </div>
        </div>

        {err && <p className={styles.err}>{err}</p>}
        <button className={styles.btnPrimary} onClick={save} disabled={loading}>
          {loading ? <Spinner /> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

function EditSlotModal({ slot, onClose, onSaved, onDeleted }) {
  const [form, setForm]         = useState({ start_time: slot.start_time, end_time: slot.end_time });
  const [loading, setLoading]   = useState(false);
  const [delLoading, setDel]    = useState(false);
  const [err, setErr]           = useState('');
  const isBooked = slot.status === 'booked';

  const save = async () => {
    setLoading(true); setErr('');
    try { await instructorAPI.updateSlot(slot.id, form); onSaved(); }
    catch (e) { setErr(e.response?.data?.detail || 'Ошибка'); }
    finally { setLoading(false); }
  };

  const del = async () => {
    if (!window.confirm('Удалить слот?')) return;
    setDel(true);
    try { await instructorAPI.deleteSlot(slot.id); onDeleted(); }
    catch (e) { setErr(e.response?.data?.detail || 'Ошибка при удалении'); }
    finally { setDel(false); }
  };

  return (
    <div className={styles.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div className={styles.modal}>
        <div className={styles.modalHeader}>
          <span className={styles.modalTitle}>Редактирование</span>
          <button className={styles.modalClose} onClick={onClose}>✕</button>
        </div>

        <div className={styles.field}>
          <label className={styles.label}>Дата</label>
          <div className={`${styles.input} ${styles.inputReadonly}`}>
            {slot.date.split('-').reverse().join('.')}
          </div>
        </div>

        <div className={styles.field}>
          <label className={styles.label}>Время</label>
          <div className={styles.timeGrid}>
            <div>
              <label className={styles.labelSm}>Начало</label>
              <input className={styles.input} type="time" value={form.start_time}
                disabled={isBooked}
                onChange={e => setForm(p => ({ ...p, start_time: e.target.value }))} />
            </div>
            <div>
              <label className={styles.labelSm}>Конец</label>
              <input className={styles.input} type="time" value={form.end_time}
                disabled={isBooked}
                onChange={e => setForm(p => ({ ...p, end_time: e.target.value }))} />
            </div>
          </div>
        </div>

        {isBooked && (
          <div className={styles.bookedBadge}>
            <span>Забронировано</span>
            <span className={styles.toggleOn} />
          </div>
        )}

        {err && <p className={styles.err}>{err}</p>}

        {!isBooked ? (
          <>
            <button className={styles.btnPrimary} onClick={save} disabled={loading}>
              {loading ? <Spinner /> : 'Сохранить'}
            </button>
            <button className={styles.btnDanger} onClick={del} disabled={delLoading}>
              {delLoading ? <Spinner /> : 'Удалить'}
            </button>
          </>
        ) : (
          <button className={styles.btnSecondary} onClick={onClose}>Закрыть</button>
        )}
      </div>
    </div>
  );
}

function ScheduleTab() {
  const [weekOffset, setWeekOffset]   = useState(0);
  const [selectedDay, setSelectedDay] = useState(new Date());
  const [slots, setSlots]             = useState([]);
  const [loading, setLoading]         = useState(true);
  const [modal, setModal]             = useState(null);
  const today = new Date();
  const weekDates = getWeekDates(weekOffset);

  const load = useCallback(() => {
    setLoading(true);
    instructorAPI.getSlots({ week: toDateStr(weekDates[0]) })
      .then(r => setSlots(Array.isArray(r.data) ? r.data : []))
      .catch(() => setSlots([]))
      .finally(() => setLoading(false));

  }, [weekOffset]);

  useEffect(() => { load(); }, [load]);

  const first = weekDates[0], last = weekDates[6];
  const monthLabel = first.getMonth() === last.getMonth()
    ? MONTHS[first.getMonth()]
    : `${MONTHS[first.getMonth()]} / ${MONTHS[last.getMonth()]}`;

  const selectedStr = toDateStr(selectedDay);
  const daySlots = slots
    .filter(s => s.date === selectedStr)
    .sort((a, b) => a.start_time.localeCompare(b.start_time));

  return (
    <div className={styles.schedulePage}>
      <h1 className={styles.pageTitle}>Расписание</h1>

      {/* Calendar */}
      <div className={styles.calendarCard}>
        <div className={styles.calendarHeader}>
          <button className={styles.navBtn} onClick={() => setWeekOffset(p => p - 1)}>←</button>
          <span className={styles.monthLabel}>{monthLabel}</span>
          <button className={styles.navBtn} onClick={() => setWeekOffset(p => p + 1)}>→</button>
        </div>
        <div className={styles.weekRow}>
          {DAYS.map(d => <span key={d} className={styles.dayName}>{d}</span>)}
        </div>
        <div className={styles.weekRow}>
          {weekDates.map((d, i) => {
            const isTd = d.toDateString() === today.toDateString();
            const isSel = d.toDateString() === selectedDay.toDateString();
            return (
              <button
                key={i}
                className={[styles.dayBtn, isTd ? styles.dayToday : '', isSel ? styles.daySelected : ''].join(' ')}
                onClick={() => setSelectedDay(new Date(d))}
              >
                {d.getDate()}
              </button>
            );
          })}
        </div>
      </div>

      {/* Day header */}
      <div className={styles.dayHeader}>
        <span className={styles.dayDate}>{fmtDate(selectedDay)}</span>
        <button className={styles.addBtn} onClick={() => setModal('create')}>+</button>
      </div>

      {/* Slots */}
      {loading ? (
        <div className={styles.loading}><Spinner /></div>
      ) : daySlots.length === 0 ? (
        <div className={styles.empty}>Нет слотов на выбранный день</div>
      ) : (
        <div className={styles.slotList}>
          {daySlots.map(slot => (
            <div
              key={slot.id}
              className={`${styles.slot} ${slot.status === 'booked' ? styles.slotBlue : styles.slotWhite}`}
              onClick={() => setModal(slot)}
            >
              <div className={styles.slotTime}>{slot.start_time} - {slot.end_time}</div>
              <div className={styles.slotTitle}>
                {slot.status === 'booked' ? (slot.student_name || 'Студент') : 'Свободно'}
              </div>
              <div className={styles.slotLocation}>
                <span>📍</span>
                Энтузиастов 12, офис 302
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Modals */}
      {modal === 'create' && (
        <CreateSlotModal
          selectedDate={selectedStr}
          onClose={() => setModal(null)}
          onSaved={() => { setModal(null); load(); }}
        />
      )}
      {modal && modal !== 'create' && (
        <EditSlotModal
          slot={modal}
          onClose={() => setModal(null)}
          onSaved={() => { setModal(null); load(); }}
          onDeleted={() => { setModal(null); load(); }}
        />
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// PROFILE TAB
// ═══════════════════════════════════════════════════════════════════════════════

function CarModal({ profile, onClose, onSaved }) {
  const [form, setForm]     = useState({
    car_brand:    profile?.car_brand    || '',
    car_color:    profile?.car_color    || '',
    car_plate:    profile?.car_plate    || '',
    car_type_kpp: profile?.car_type_kpp || 'МКПП',
  });
  const [loading, setLoading] = useState(false);
  const [err, setErr]       = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try { await instructorAPI.updateCar(form); onSaved(); }
    catch (e) { setErr(e.response?.data?.detail || 'Ошибка'); }
    finally { setLoading(false); }
  };

  return (
    <div className={styles.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div className={styles.modal}>
        <div className={styles.modalHeader}>
          <span className={styles.modalTitle}>Автомобиль</span>
          <button className={styles.modalClose} onClick={onClose}>✕</button>
        </div>
        {[
          { key: 'car_brand', label: 'Марка автомобиля', placeholder: 'Lada Granta' },
          { key: 'car_color', label: 'Цвет',             placeholder: 'Белый'       },
          { key: 'car_plate', label: 'Регистрационный номер', placeholder: 'X000XX774' },
        ].map(({ key, label, placeholder }) => (
          <div className={styles.field} key={key}>
            <label className={styles.label}>{label}</label>
            <input className={styles.input} placeholder={placeholder}
              value={form[key]} onChange={e => setForm(p => ({ ...p, [key]: e.target.value }))} />
          </div>
        ))}
        <div className={styles.field}>
          <label className={styles.label}>Тип КПП</label>
          <select className={styles.input} value={form.car_type_kpp}
            onChange={e => setForm(p => ({ ...p, car_type_kpp: e.target.value }))}>
            <option value="МКПП">МКПП (механика)</option>
            <option value="АКПП">АКПП (автомат)</option>
          </select>
        </div>
        {err && <p className={styles.err}>{err}</p>}
        <button className={styles.btnPrimary} onClick={save} disabled={loading}>
          {loading ? <Spinner /> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

function LimitModal({ profile, onClose, onSaved }) {
  const [limit, setLimit]   = useState(profile?.weekly_limit ?? 3);
  const [loading, setLoading] = useState(false);
  const [err, setErr]       = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try { await instructorAPI.updateLimit({ weekly_limit: limit }); onSaved(); }
    catch (e) { setErr(e.response?.data?.detail || 'Ошибка'); }
    finally { setLoading(false); }
  };

  return (
    <div className={styles.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div className={styles.modal}>
        <div className={styles.modalHeader}>
          <span className={styles.modalTitle}>Лимит занятий</span>
          <button className={styles.modalClose} onClick={onClose}>✕</button>
        </div>
        <p style={{ fontSize: 14, color: 'var(--gray-text, #6B7280)', marginBottom: 16, lineHeight: 1.5 }}>
          Максимальное количество занятий в неделю, на которое может записаться студент.
        </p>
        <div className={styles.limitRow}>
          <button className={styles.limitBtn} onClick={() => setLimit(p => Math.max(1, p - 1))}>−</button>
          <span className={styles.limitVal}>{limit}</span>
          <button className={styles.limitBtn} onClick={() => setLimit(p => Math.min(10, p + 1))}>+</button>
        </div>
        {err && <p className={styles.err}>{err}</p>}
        <button className={styles.btnPrimary} onClick={save} disabled={loading}>
          {loading ? <Spinner /> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

function ProfileTab() {
  const { logout }          = useAuth();
  const navigate            = useNavigate();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal, setModal]   = useState(null);

  const load = () => {
    instructorAPI.getProfile()
      .then(r => setProfile(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  };
  useEffect(() => { load(); }, []);

  const fullName = profile
    ? [profile.last_name, profile.first_name, profile.patronymic].filter(Boolean).join(' ')
    : '—';

  const carLabel = profile?.car_brand
    ? `${profile.car_color ? profile.car_color + ' ' : ''}${profile.car_brand} ${profile.car_plate || ''}`.trim()
    : 'Не указан';

  return (
    <div className={styles.profilePage}>
      <div className={styles.profileHeader}>
        <h1 className={styles.pageTitle}>Профиль</h1>
        <button style={{ background: 'none', border: 'none', fontSize: 22, cursor: 'pointer' }}>🔔</button>
      </div>

      {loading ? (
        <div className={styles.loading}><Spinner /></div>
      ) : (
        <>
          <div className={styles.avatar}>
            <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
              <circle cx="24" cy="18" r="10" fill="#b0b8c9" />
              <ellipse cx="24" cy="42" rx="18" ry="10" fill="#b0b8c9" />
            </svg>
          </div>
          <div className={styles.profileName}>{fullName}</div>

          <div className={styles.infoCard} onClick={() => setModal('car')}>
            <div className={styles.infoCardHeader}>
              <span className={styles.infoCardTitle}>Автомобиль</span>
              <span className={styles.infoCardEdit}>✎</span>
            </div>
            <div className={styles.infoCardValue}>{carLabel}</div>
          </div>

          <div className={styles.infoCard} onClick={() => setModal('limit')}>
            <div className={styles.infoCardHeader}>
              <span className={styles.infoCardTitle}>Лимит</span>
              <span className={styles.infoCardEdit}>✎</span>
            </div>
            <div className={styles.infoCardValueMuted}>
              Максимальное количество занятий в неделю, на которое может записаться студент —{' '}
              <strong style={{ color: '#1A1A2E' }}>{profile?.weekly_limit ?? 3}</strong>.
            </div>
          </div>

          <button className={styles.logoutBtn} onClick={() => { logout(); navigate('/login'); }}>
            Выйти
          </button>
        </>
      )}

      {modal === 'car'   && <CarModal   profile={profile} onClose={() => setModal(null)} onSaved={() => { setModal(null); load(); }} />}
      {modal === 'limit' && <LimitModal profile={profile} onClose={() => setModal(null)} onSaved={() => { setModal(null); load(); }} />}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// REQUESTS TAB (заявки студентов)
// ═══════════════════════════════════════════════════════════════════════════════

function RequestsTab() {
  const [students, setStudents] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    instructorAPI.getStudents()
      .then(r => setStudents(Array.isArray(r.data) ? r.data : []))
      .catch(() => setStudents([]))
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className={styles.requestsPage}>
      <h1 className={styles.pageTitle}>Студенты</h1>
      {loading ? (
        <div className={styles.loading}><Spinner /></div>
      ) : students.length === 0 ? (
        <div className={styles.empty}>Студенты не назначены</div>
      ) : students.map(s => (
        <div key={s.id} className={styles.requestCard}>
          <div className={styles.requestName}>{s.full_name}</div>
          <div className={styles.requestMeta}>
            <span>📞 {s.phone_number}</span>
            <span>🚗 {s.type_kpp || '—'} · {s.count_lessons} ч. практики</span>
            {s.tariff_name && <span>📋 {s.tariff_name}</span>}
          </div>
        </div>
      ))}
    </div>
  );
}

